public class ETGSalesLineDataEventHandler
{
    static Amount lastLineAmount;
    static Qty    lastSalesQty;
    static real   lastPriceUnit;

}

Method.Source:
/// <summary>
/// Recalculates SalesPrice based on LineAmount / SalesQty
/// </summary>
public static void recalcPrice(SalesLine _salesLine)
{
    if (_salesLine.LineAmount != 0 && _salesLine.SalesQty != 0)
    {
        real calculatedPrice = (_salesLine.LineAmount * _salesLine.PriceUnit) / _salesLine.SalesQty;

        if (_salesLine.SalesPrice != calculatedPrice)
        {
            _salesLine.SalesPrice = calculatedPrice;
        }
    }
}

[FormDataFieldEventHandler(formDataFieldStr(SalesTable, SalesLine, LineAmount), FormDataFieldEventType::Modified)]
public static void SalesLine_LineAmount_OnModified(FormDataObject sender, FormDataFieldEventArgs e)
{
    FormDataSource  salesLine_ds = sender.datasource();
    SalesLine       salesLine    = salesLine_ds.cursor() as SalesLine;

    ETGSalesLineDataEventHandler::lastLineAmount = salesLine.LineAmount;
    ETGSalesLineDataEventHandler::lastSalesQty   = salesLine.SalesQty;
    ETGSalesLineDataEventHandler::lastPriceUnit  = salesLine.PriceUnit;

    ETGSalesLineDataEventHandler::recalcPrice(salesLine);
    salesLine_ds.refresh();
}

[FormDataFieldEventHandler(formDataFieldStr(SalesTable, InventDim, InventSiteId), FormDataFieldEventType::Validated)]
public static void InventDim_InventSiteId_OnValidated(FormDataObject sender, FormDataFieldEventArgs e)
{
    FormDataSource  inventDim_ds = sender.datasource();
    FormDataSource  salesLine_ds = inventDim_ds.formRun().dataSource(formDataSourceStr(SalesTable, SalesLine));
    SalesLine       salesLine    = salesLine_ds.cursor() as SalesLine;

    Amount  lineAmt   = ETGSalesLineDataEventHandler::lastLineAmount;
    Qty     salesQty  = salesLine.SalesQty  != 0 ? salesLine.SalesQty  : ETGSalesLineDataEventHandler::lastSalesQty;
    real    priceUnit = salesLine.PriceUnit != 0 ? salesLine.PriceUnit : ETGSalesLineDataEventHandler::lastPriceUnit;

    if (lineAmt != 0 && salesQty != 0)
    {
        real calculatedPrice = (lineAmt * priceUnit) / salesQty;

        salesLine.SalesPrice = calculatedPrice;
        salesLine.LineAmount = lineAmt;

        salesLine_ds.research(false);
    }
}

[FormDataSourceEventHandler(formDataSourceStr(SalesTable, SalesLine), FormDataSourceEventType::Activated)]
public static void SalesLine_OnActivated(FormDataSource sender, FormDataSourceEventArgs e)
{
    SalesLine salesLine = sender.cursor() as SalesLine;

    Amount  lineAmt   = ETGSalesLineDataEventHandler::lastLineAmount;
    Qty     salesQty  = salesLine.SalesQty  != 0 ? salesLine.SalesQty  : ETGSalesLineDataEventHandler::lastSalesQty;
    real    priceUnit = salesLine.PriceUnit != 0 ? salesLine.PriceUnit : ETGSalesLineDataEventHandler::lastPriceUnit;

    if (lineAmt != 0 && salesQty != 0)
    {
        real calculatedPrice = (lineAmt * priceUnit) / salesQty;

        if (salesLine.SalesPrice != calculatedPrice)
        {
            salesLine.SalesPrice = calculatedPrice;
            sender.refresh();
        }
    }
}

[FormDataSourceEventHandler(formDataSourceStr(SalesTable, SalesLine), FormDataSourceEventType::ValidatingWrite)]
public static void SalesLine_OnValidatingWrite(FormDataSource sender, FormDataSourceEventArgs e)
{
    SalesLine salesLine = sender.cursor() as SalesLine;

    Amount  lineAmt   = ETGSalesLineDataEventHandler::lastLineAmount;
    Qty     salesQty  = salesLine.SalesQty  != 0 ? salesLine.SalesQty  : ETGSalesLineDataEventHandler::lastSalesQty;
    real    priceUnit = salesLine.PriceUnit != 0 ? salesLine.PriceUnit : ETGSalesLineDataEventHandler::lastPriceUnit;

    if (lineAmt != 0 && salesQty != 0)
    {
        real calculatedPrice = (lineAmt * priceUnit) / salesQty;
        salesLine.SalesPrice = calculatedPrice;
        salesLine.LineAmount = lineAmt;

        sender.refresh();
    }
}
